import{_ as r,o as n,c as o,a6 as s}from"./chunks/framework.DxlbIVIm.js";const y=JSON.parse('{"title":"序章｜預告片式分鏡表（戀綜開場 → 嘉賓入場 → 男主視角）","description":"","frontmatter":{},"headers":[],"relativePath":"story/序章_預告片式分鏡表.md","filePath":"story/序章_預告片式分鏡表.md"}'),g={name:"story/序章_預告片式分鏡表.md"};function d(e,t,a,l,i,c){return n(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="序章-預告片式分鏡表-戀綜開場-→-嘉賓入場-→-男主視角" tabindex="-1">序章｜預告片式分鏡表（戀綜開場 → 嘉賓入場 → 男主視角） <a class="header-anchor" href="#序章-預告片式分鏡表-戀綜開場-→-嘉賓入場-→-男主視角" aria-label="Permalink to &quot;序章｜預告片式分鏡表（戀綜開場 → 嘉賓入場 → 男主視角）&quot;">​</a></h1><p>本表供 <strong>「先綜藝、後男主」</strong> 改版使用。台詞細節以 <a href="./dialogues.html">劇情對話總覽</a> 與 <code>chapter_day0_prologue.json</code> 為準；此處負責 <strong>時間節奏、鏡頭意圖、與舊段落的對接點</strong>。</p><p><strong>假設片長</strong>：遊戲內可播 <strong>約 2:00～3:00</strong>（或再加可跳過的加長版）；每格約 <strong>12～15 秒</strong>，玩家可按一次 <strong>略過蒙太奇</strong> 直接進互動場景。</p><hr><h2 id="角色入場順序-與現行文本對齊" tabindex="-1">角色入場順序（與現行文本對齊） <a class="header-anchor" href="#角色入場順序-與現行文本對齊" aria-label="Permalink to &quot;角色入場順序（與現行文本對齊）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">順序</th><th>角色</th><th>對接 <code>dialogues.md</code></th></tr></thead><tbody><tr><td style="text-align:center;">1～3</td><td>體育男 → 暖男 → 高冷男</td><td>§0.3 客廳集合</td></tr><tr><td style="text-align:center;">4～6</td><td>搖滾少女 → 清純少女 → 運動少女</td><td>§0.4 女主角依序登場</td></tr><tr><td style="text-align:center;">7</td><td><strong>男主角（VIP）</strong></td><td>§0.1 邀請可改為 <strong>VO／閃回</strong>；進場後接 §0.3 未寫完的「你進門」或改寫首句</td></tr><tr><td style="text-align:center;">—</td><td>貴氣大小姐、地雷少女</td><td>若本段序章也要亮相，建議加在運動少女之後、男主之前，或 <strong>Day0 夜／Day1 早</strong> 再登場，避免預告段過長</td></tr></tbody></table><hr><h2 id="分鏡表-粗剪节拍" tabindex="-1">分鏡表（粗剪节拍） <a class="header-anchor" href="#分鏡表-粗剪节拍" aria-label="Permalink to &quot;分鏡表（粗剪节拍）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">格</th><th style="text-align:center;">时長(約)</th><th>畫面／鏡頭</th><th>聲音／字幕</th><th>互動／程式備註</th><th>對接資產／劇本</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>01</strong></td><td style="text-align:center;">12s</td><td><strong>黑場</strong> → 節目 LOGO（可戲仿串流「大型字卡＋音效」）標題 <strong>《禁忌的 Show》</strong>；0.5s <strong>警示字卡</strong>（成年向／虛構綜藝）</td><td>低沉 <strong>當一聲</strong> + 環境底噪；VO（製作人偏處理過的聲線）：「歡迎收看——」</td><td>可在此設 <strong>按住跳過</strong> 的起點</td><td>新建 UI；VO 可取自 §0.2 首句變體</td></tr><tr><td style="text-align:center;"><strong>02</strong></td><td style="text-align:center;">14s</td><td><strong>快剪</strong>：無人紅毯／別墅遠景／監視器紅燈／合約文件翻頁（不露全文）／手機沒收盤特寫一閃</td><td>節奏 <strong>重拍</strong>；VO：「在這裡，慾望不需要被隱藏。」（§0.2 精簡）</td><td>純演出</td><td>呼應 <code>CG05_霧中孤島別墅</code>、製作團隊感</td></tr><tr><td style="text-align:center;"><strong>03</strong></td><td style="text-align:center;">12s</td><td>字幕：<strong>男嘉賓入場</strong>。體育男 <strong>大力</strong> 推門／扛運動包；鏡頭帶 <strong>肌肉與笑</strong></td><td>體育男台詞可只留 <strong>半句</strong>（例：「又來一個…」改為對空氣／鏡頭）其餘 <strong>進正式場再補完</strong></td><td>無</td><td>§0.3 體育男</td></tr><tr><td style="text-align:center;"><strong>04</strong></td><td style="text-align:center;">13s</td><td>暖男 <strong>端飲品</strong>、對鏡頭 <strong>禮貌一笑</strong>（綜藝感）；切 <strong>側拍</strong> 像有攝影師</td><td>暖男 <strong>半句</strong> VO；環境：瓷器聲</td><td>無</td><td>§0.3 暖男</td></tr><tr><td style="text-align:center;"><strong>05</strong></td><td style="text-align:center;">14s</td><td>高冷男 <strong>雜誌遮臉／只露眼睛</strong>；窗外 <strong>一瞬閃光</strong> 暗示隱藏鏡頭</td><td>高冷男 <strong>一句</strong>（§0.3）+ <strong>環境靜</strong></td><td>無</td><td>§0.3 高冷男</td></tr><tr><td style="text-align:center;"><strong>06</strong></td><td style="text-align:center;">15s</td><td>客廳 <strong>全景</strong>：三男 <strong>呈三角站位</strong>；角落 <strong>未坐滿的沙發</strong>（預留 <strong>最後一位</strong>）</td><td><strong>評論式字幕</strong>（可選）：「火藥味／紳士／刺蝟」三詞一閃</td><td>可選：<strong>點一個角落</strong> 只看該男表情（+1 句內心旁白，不影響數值）</td><td>對應 timeline「男嘉賓集合」</td></tr><tr><td style="text-align:center;"><strong>07</strong></td><td style="text-align:center;">13s</td><td>字幕：<strong>女嘉賓入場</strong>。搖滾少女 <strong>耳機／推門</strong>；<strong>重金屬漏音</strong> 一瞬拉滿再壓低</td><td>搖滾少女 §0.4 <strong>第 1～2 句</strong> 剪短；體育男起哄 <strong>只留笑聲</strong></td><td>無</td><td>§0.4-1、<code>CG</code> 搖滾系</td></tr><tr><td style="text-align:center;"><strong>08</strong></td><td style="text-align:center;">14s</td><td>清純少女 <strong>門縫光／鞠躬</strong>；暖男 <strong>起身</strong> 動作 <strong>慢動作 0.3s</strong></td><td>清純少女 <strong>緊張句</strong>；高冷男冷句 <strong>只留後半</strong> 增加神秘</td><td>可在此 <strong>第一個輕互動</strong>：視線停 <strong>暖男／玩家座向空位</strong>（為後面選項埋伏筆）</td><td>§0.4-2</td></tr><tr><td style="text-align:center;"><strong>09</strong></td><td style="text-align:center;">14s</td><td>運動少女 <strong>彈力進門</strong>；與體育男 <strong>擊拳</strong> 類快剪；<strong>指鏡頭／指「還空著的位子」</strong></td><td>運動少女 <strong>招呼句</strong> + <strong>「VIP…」半句</strong> 可 <strong>切掉</strong> 留到男主進場後再說</td><td>無</td><td>§0.4-3</td></tr><tr><td style="text-align:center;"><strong>10</strong></td><td style="text-align:center;">12s</td><td><strong>製作人半臉面具</strong> 走入畫或 <strong>監視螢幕出現他的側臉</strong>；<strong>全場安靜</strong></td><td><strong>規則宣告壓縮版</strong>（§0.2 四句 → <strong>兩句 VO</strong>）：「進門後只剩好感」「交出手機」</td><td>若 <strong>政策／節奏</strong> 需溫和，可 <strong>強調「節目規則」</strong> 弱化威脅語氣</td><td>§0.2、<code>CG06_製作人迎接</code></td></tr><tr><td style="text-align:center;"><strong>11</strong></td><td style="text-align:center;">15s</td><td><strong>停頓</strong>：大門 <strong>第二次開啟</strong> 的 <strong>剪影</strong>；字幕：<strong>「最后一位——特邀 VIP」</strong>（或「保密嘉賓」）</td><td><strong>只有腳步／心跳／低頻</strong>；VO 製作人：「該你上場了。」（新建一筆）</td><td><strong>轉場點</strong>：按下 <strong>繼續</strong> 後進男主線</td><td>衔接下格</td></tr><tr><td style="text-align:center;"><strong>12</strong></td><td style="text-align:center;">14s</td><td><strong>男主視角開始</strong>：二選一節奏——<br><strong>A.</strong> 快速 <strong>§0.1 邀請函</strong> 螢幕特寫蒙太奇（2～3 個 cut）<br><strong>B.</strong> 直接 <strong>豪華車內／窗外別墅</strong>（<code>CG04</code>）</td><td><strong>玩家第一人稱內心</strong>（§0.1 精簡為 2～3 句）避免重覆長独白</td><td>若選 A→B：<strong>自動</strong>；若只做 B：可略過 A</td><td>§0.1、<code>CG02/03/04</code></td></tr><tr><td style="text-align:center;"><strong>13</strong></td><td style="text-align:center;">13s</td><td><strong>車門／大門</strong>：男主 <strong>正式踏進紅毯或門檻</strong>；鏡頭 <strong>終於給正臉或背影＋名牌</strong>（綜藝 lower third）</td><td>現場 <strong>雜音拉起</strong>（像錄影開始）</td><td><strong>第一天可操作</strong>：停止 auto，進 <strong>完整對話模式</strong></td><td><code>CG06</code> → 進 §0.3 <strong>玩家進門後</strong> 全員台詞</td></tr><tr><td style="text-align:center;"><strong>14</strong></td><td style="text-align:center;">12s</td><td><strong>收束</strong>：三男視線 <strong>同時抬頭</strong>；其中一人 <strong>先開腔</strong>（接 §0.3 體育男完整挑釁）；或製作人 <strong>拍手</strong>／「請就座」</td><td>音樂 <strong>揚起</strong> 接 <strong>主選單／Day0 主場</strong> BGM</td><td>若 §0.4 女主已在蒙太奇進場，此格僅 <strong>補對白</strong>；若希望 <strong>女主第二次進場</strong>，可把 §0.4 整段移到此格後</td><td>對話 JSON 需 <strong>拆「蒙太奇版」與「完整版」</strong> 兩套 line id</td></tr></tbody></table><hr><h2 id="與舊結構的差異-實作備忘" tabindex="-1">與舊結構的差異（實作備忘） <a class="header-anchor" href="#與舊結構的差異-實作備忘" aria-label="Permalink to &quot;與舊結構的差異（實作備忘）&quot;">​</a></h2><ol><li><strong>§0.1 不再一開始就播滿</strong>：改為 <strong>第 11～12 格</strong> 的 <strong>短 VO／閃回</strong>，避免前 3 分鐘都是「只有自己」。</li><li><strong>§0.2 規則宣告</strong>：預告段用 <strong>雙句</strong>，完整四句留在 <strong>進別墅后</strong> 或 <strong>製作人近景 CG</strong>。</li><li><strong>§0.3 / §0.4</strong>：預告里 <strong>只給切片</strong>；<strong>完整吵架、選肢</strong> 在 <strong>第 13 格後</strong> 接回現有表格台詞。</li><li><strong>chapter_day0_prologue.json</strong>：前段敘述若仍是「你騎單車」連發，可改成 <strong>(a)</strong> 維持於第 12 格蒙太奇 <strong>(b)</strong> 或濃縮成 2 條 <code>narrator</code> 再接進門。</li></ol><hr><h2 id="可選-對標《badly-in-love》式-一句賣點-示例-可再改詞" tabindex="-1">可選：對標《Badly in Love》式 <strong>一句賣點</strong>（示例，可再改詞） <a class="header-anchor" href="#可選-對標《badly-in-love》式-一句賣點-示例-可再改詞" aria-label="Permalink to &quot;可選：對標《Badly in Love》式 **一句賣點**（示例，可再改詞）&quot;">​</a></h2><ul><li>畫面：慢動作＋拳頭／香檳／眼神互瞪的快速混剪（虛構、非暴力亦可改成 <strong>撞肩／搶話筒</strong>）。</li><li>大字幕：<strong>「心動會上癮——越界會上癮。」</strong>（僅示例，避免与 Netflix 文案雷同）</li><li>放置位置：<strong>格 02 末尾</strong> 或 <strong>格 10 規則宣告前</strong>。</li></ul><hr><h2 id="修訂紀錄" tabindex="-1">修訂紀錄 <a class="header-anchor" href="#修訂紀錄" aria-label="Permalink to &quot;修訂紀錄&quot;">​</a></h2><table tabindex="0"><thead><tr><th>日期</th><th>說明</th></tr></thead><tbody><tr><td>2026-05-14</td><td>初版：對齊 <code>dialogues.md</code> Day0 §0.1～0.4 與序章 CG 編號習慣</td></tr></tbody></table>',18)])])}const x=r(g,[["render",d]]);export{y as __pageData,x as default};
